using System;
using System.Collections.Generic;
using System.Linq;
using System.Net.Http;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace WebhookProxy
{
    [ApiController]
    public class ProxyController : ControllerBase
    {
        private readonly Dictionary<string, Uri> _webhooks;
        private readonly HttpClient _httpClient;
        private readonly ILogger<ProxyController> _logger;

        public ProxyController(HttpClient httpClient, ILogger<ProxyController> logger)
        {
            _httpClient = httpClient;
            _logger = logger;
            _webhooks = new Dictionary<string, Uri>();
        }

        [HttpPost("forward/{id}")]
        public async Task<IActionResult> Forward([FromRoute] string id, [FromBody] Uri url)
        {
            if (_webhooks.ContainsKey(id))
            {
                _webhooks[id] = url;
                return Ok();
            }
            else
            {
                return NotFound();
            }
        }

        [HttpPost("{id}")]
        public async Task<IActionResult> Proxy([FromRoute] string id, [FromBody] dynamic data)
        {
            if (!_webhooks.TryGetValue(id, out var webhookUrl))
            {
                return NotFound();
            }

            try
            {
                HttpResponseMessage response = await _httpClient.PostAsJsonAsync(webhookUrl, data);
                response.EnsureSuccessStatusCode();
                return Ok();
            }
            catch (HttpRequestException ex)
            {
                _logger.LogError(ex, $"Failed to forward request for id {id}: {ex.Message}");
                return StatusCode(500, "Internal server error");
            }
        }
